7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive that has exactly 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should keep a live cell alive that has exactly 3 live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("should kill a live cell that has 4 live neighbors (overpopulation)", () => {
23	    const cross = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
24	    const result = nextGeneration(cross);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it("should bring a dead cell to life that has exactly 3 live neighbors (reproduction)", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("should keep a block pattern unchanged as a still life", () => {
32	    const block = [[0, 0], [1, 0], [0, 1], [1, 1]];
33	    const result = nextGeneration(block);
34	    const sorted = (cells: number[][]) =>
35	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
36	    expect(sorted(result)).toEqual(sorted(block));
37	  });
